"""
Anna Lipsync — Modal deployment
Replaces the RunPod fizzy-clover renderer with a serverless Modal GPU endpoint.

Endpoint: POST /animate
  Input:  raw audio bytes (audio/wav or audio/webm), Content-Type header set
  Output: raw MP4 bytes (video/mp4) of Anna speaking the audio

Usage:
  modal deploy modal_lipsync.py
  # → prints URL like https://littf02--anna-lipsync-web-app.modal.run
  # Set rendererUrl in config.js to that URL
"""

import modal

# Anna reference face — embedded as base64 to survive container rebuilds
ANNA_FACE_B64 = ""

app = modal.App("anna-lipsync")

# ── Image build ───────────────────────────────────────────────────────────────
# Clones SadTalker, installs deps, downloads all checkpoints.
# Modal caches every layer — this only runs once; rebuilds only if commands change.

image = (
    modal.Image.from_registry(
        "nvidia/cuda:11.8.0-cudnn8-devel-ubuntu22.04",
        add_python="3.10",
    )
    .apt_install(
        "git", "ffmpeg", "wget", "bzip2", "unzip",
        "libgl1", "libglib2.0-0", "libsm6", "libxext6", "libxrender1",
        "libgomp1",
    )
    .pip_install(
        "torch==2.1.0",
        "torchvision==0.16.0",
        "torchaudio==2.1.0",
        extra_index_url="https://download.pytorch.org/whl/cu118",
    )
    .run_commands(
        # Clone SadTalker
        "git clone https://github.com/OpenTalker/SadTalker /sadtalker",
        # Install Python deps (requirements.txt has face_alignment, imageio, etc.)
        "cd /sadtalker && pip install -r requirements.txt",
        # Download model checkpoints — baked into image so zero download at runtime
        "mkdir -p /sadtalker/checkpoints /sadtalker/gfpgan/weights",
        "cd /sadtalker && bash scripts/download_models.sh 2>&1 | tail -20",
    )
    # Bundle Anna's reference face image
    .add_local_file("/tmp/anna-face.png", "/anna_face.png")
)

# ── Web app ────────────────────────────────────────────────────────────────────
@app.function(
    image=image,
    gpu="A10G",
    timeout=120,
    scaledown_window=300,   # stay warm 5 min after last call → no cold starts mid-demo
    # keep_warm=1,          # uncomment to always have one instance hot ($0.65/hr idle cost)
)
@modal.concurrent(max_inputs=4)
@modal.asgi_app()
def web_app():
    import sys, os, subprocess, tempfile, glob, base64, shutil
    from fastapi import FastAPI, Request
    from fastapi.responses import Response, JSONResponse

    # Write Anna's face to a known path on this container's filesystem.
    # We use base64 embedded in the source code (not add_local_file) so it's
    # guaranteed to exist regardless of Modal image caching behaviour.
    FACE_TEMPLATE = "/tmp/anna_face_template.png"
    if not os.path.exists(FACE_TEMPLATE):
        with open(FACE_TEMPLATE, "wb") as _f:
            _f.write(base64.b64decode(ANNA_FACE_B64))
        print(f"[lipsync] Wrote Anna face template to {FACE_TEMPLATE}")

    sys.path.insert(0, "/sadtalker")
    from src.gradio_demo import SadTalker

    # Load model once per container — cached for the lifetime of the warm instance
    print("[lipsync] Loading SadTalker…")
    sad_talker = SadTalker(
        checkpoint_path="/sadtalker/checkpoints",
        config_path="/sadtalker/src/config",
        lazy_load=True,
    )
    print("[lipsync] SadTalker ready ✓")

    api = FastAPI()

    @api.get("/health")
    def health():
        return {"ok": True, "model": "sadtalker"}

    @api.post("/animate")
    async def animate(request: Request):
        audio_bytes = await request.body()
        if not audio_bytes:
            return JSONResponse({"error": "no audio"}, status_code=400)

        content_type = request.headers.get("content-type", "audio/wav")
        ext = ".webm" if "webm" in content_type else ".wav"

        with tempfile.TemporaryDirectory() as tmpdir:
            # SadTalker moves (not copies) the source image — copy from template each call
            face_path = os.path.join(tmpdir, "anna_face.png")
            shutil.copy(FACE_TEMPLATE, face_path)

            audio_in = os.path.join(tmpdir, "audio" + ext)
            wav_path  = os.path.join(tmpdir, "audio.wav")

            with open(audio_in, "wb") as f:
                f.write(audio_bytes)

            # Convert webm → wav if needed (SadTalker needs WAV)
            if ext != ".wav":
                subprocess.run(
                    ["ffmpeg", "-y", "-i", audio_in, "-ar", "16000", "-ac", "1", wav_path],
                    capture_output=True, check=True,
                )
            else:
                wav_path = audio_in

            # Run SadTalker inference. preprocess="full" keeps the source image's
            # full 448x672 framing and pastes the animated face back — output
            # matches idle.mp4 dimensions so the iframe video swap doesn't look
            # zoomed in.
            result_path = sad_talker.test(
                source_image=face_path,
                driven_audio=wav_path,
                preprocess="full",
                still_mode=True,       # minimal head movement → cleaner avatar look
                use_enhancer=False,    # skip GFPGAN → faster
                batch_size=1,
                size=256,              # face-region inference resolution; final video stays at source size
                pose_style=0,
                exp_scale=1.0,
                use_ref_video=False,
                use_idle_mode=False,
                use_blink=False,       # no blinking animation
                result_dir=tmpdir,
            )

            # SadTalker returns the video path or writes to result_dir — find the mp4
            if not result_path or not os.path.exists(result_path):
                # Fallback: glob for any mp4 in tmpdir
                mp4s = glob.glob(os.path.join(tmpdir, "**/*.mp4"), recursive=True)
                if not mp4s:
                    return JSONResponse({"error": "no output video generated"}, status_code=500)
                result_path = mp4s[0]

            # SadTalker `full` mode writes MPEG-4 Simple Profile, which Chrome
            # can't decode. Re-encode to H.264 yuv420p so the iframe video
            # element actually plays the clip instead of showing a black frame.
            web_path = os.path.join(tmpdir, "out_h264.mp4")
            subprocess.run(
                ["ffmpeg", "-y", "-i", result_path,
                 "-c:v", "libx264", "-profile:v", "baseline",
                 "-pix_fmt", "yuv420p", "-movflags", "+faststart",
                 "-c:a", "aac", "-b:a", "128k",
                 web_path],
                capture_output=True, check=True,
            )
            with open(web_path, "rb") as f:
                video_bytes = f.read()

        return Response(
            content=video_bytes,
            media_type="video/mp4",
            headers={"Access-Control-Allow-Origin": "*"},
        )

    return api
